Interpretation on the Original Scale
A one kV increase results in a \(\exp(-0.507) = 0.60\) multiplicative change in median breakdown time — a 40% decrease.

tidy(lmout, conf.int = TRUE) |&gt;
  filter(term == "Voltage") |&gt;
  select(estimate, conf.low, conf.high) |&gt;
  mutate(across(everything(), exp))

# A tibble: 1 × 3
  estimate conf.low conf.high
     &lt;dbl&gt;    &lt;dbl&gt;     &lt;dbl&gt;
1    0.602    0.537     0.675



tidy(lmout, conf.int = TRUE) |&gt;
  filter(term == "Voltage") |&gt;
  transmute(
    pct_change      = (1 - exp(estimate)) * 100,
    pct_change_low  = (1 - exp(conf.high)) * 100,
    pct_change_high = (1 - exp(conf.low)) * 100
  )

# A tibble: 1 × 3
  pct_change pct_change_low pct_change_high
       &lt;dbl&gt;          &lt;dbl&gt;           &lt;dbl&gt;
1       39.8           32.5            46.3
